"use strict";(self.webpackChunkblog=self.webpackChunkblog||[]).push([[4],{6612:function(n){n.exports=JSON.parse('{"blogPosts":[{"id":"/cl3893xld06owmgnv8j2mfmgn","metadata":{"permalink":"/zh/cl3893xld06owmgnv8j2mfmgn","source":"@site/blog/cl3893xld06owmgnv8j2mfmgn.md","title":"Toast 2 - \u5feb\u901f\u5c0e\u5165 Bootstrap 5 \u9032\u884c\u958b\u767c","description":"Toast 2 - \u5feb\u901f\u5c0e\u5165 Bootstrap 5 \u9032\u884c\u958b\u767c","date":"2022-05-16T00:00:00.000Z","formattedDate":"2022\u5e745\u670816\u65e5","tags":[{"label":"bootstrap","permalink":"/zh/tags/bootstrap"},{"label":"toast","permalink":"/zh/tags/toast"}],"readingTime":4.5,"truncated":true,"authors":[{"name":"Callum","title":"Front End Engineer","url":"https://github.com/callumzhong","imageURL":"https://github.com/callumzhong.png","key":"callum"}],"frontMatter":{"title":"Toast 2 - \u5feb\u901f\u5c0e\u5165 Bootstrap 5 \u9032\u884c\u958b\u767c","date":"2022-05-16T00:00:00.000Z","authors":"callum","tags":["bootstrap","toast"]},"nextItem":{"title":"Toast 1 - Custom Error - JavaScript","permalink":"/zh/cl2oclcxw00fzkhnv02fy1wvo"}},"content":"## Toast 2 - \u5feb\u901f\u5c0e\u5165 Bootstrap 5 \u9032\u884c\u958b\u767c\\n\\n---\\n\\n## \u524d\u8a00\\n\\n\u96a8\u8457 Bootstrap 5 \u7684\u4f86\u81e8  \\n\u958b\u767c\u8005\u8a72\u600e\u9ebc\u9762\u5c0d\u516c\u53f8\u7684\u5c0e\u5165\u9700\u6c42 ?\\n\\n\x3c!--truncate--\x3e\\n\\n---\\n\\n## \u5efa\u7acb\u5c08\u6848\\n\\n---\\n\\n1. \u65b0\u589e project \u8cc7\u6599\u593e\\n2. \u57f7\u884c `yarn init -y`\\n3. \u5b89\u88dd [Prarcel](https://parceljs.org/docs/) \u69cb\u5efa\u5de5\u5177\\n\\n```\\nyarn add --dev parcel\\n```\\n\\n4. \u65b0\u589e\u4ee5\u4e0b\u8cc7\u6599\u593e\u7d50\u69cb\\n   ![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1652672167208/3fOQLZkZP.png align=\\"left\\")\\n\\n---\\n\\n## \u5b89\u88dd\u8207\u914d\u7f6e\\n\\n---\\n\\n\u63a5\u4e0b\u4f86\u6211\u5011\u958b\u59cb\u5b89\u88dd [Bootstrap 5](https://getbootstrap.com/)\\n\\n```\\nyarn add bootstrap@latest\\n```\\n\\n\u5b89\u88dd\u597d\u5f8c\uff0c\u8acb\u5230\u4ee5\u4e0b\u8def\u5f91\u6253\u958b\u6a94\u6848\u8907\u88fd\u5167\u5bb9\\n\\n```\\nnode_modules\\\\bootstrap\\\\scss\\\\bootstrap.scss\\n```\\n\\n\u8acb\u5230 project \u7684 src/scss \u8cc7\u6599\u593e\u4e0b\u5efa\u7acb app.scss \u628a\u5167\u5bb9\u8cbc\u4e0a\\n\u4e26\u4fee\u6539 @import \u9023\u7d50\\n\\n```scss\\n/*!\\n * Bootstrap v5.1.3 (https://getbootstrap.com/)\\n * Copyright 2011-2021 The Bootstrap Authors\\n * Copyright 2011-2021 Twitter, Inc.\\n * Licensed under MIT (https://github.com/twbs/bootstrap/blob/main/LICENSE)\\n */\\n\\n// scss-docs-start import-stack\\n// Configuration\\n@import \'~bootstrap/scss/functions\';\\n@import \'~bootstrap/scss/variables\';\\n@import \'~bootstrap/scss/mixins\';\\n@import \'~bootstrap/scss/utilities\';\\n\\n// Layout & components\\n@import \'~bootstrap/scss/root\';\\n@import \'~bootstrap/scss/reboot\';\\n@import \'~bootstrap/scss/type\';\\n@import \'~bootstrap/scss/images\';\\n@import \'~bootstrap/scss/containers\';\\n@import \'~bootstrap/scss/grid\';\\n@import \'~bootstrap/scss/tables\';\\n@import \'~bootstrap/scss/forms\';\\n@import \'~bootstrap/scss/buttons\';\\n@import \'~bootstrap/scss/transitions\';\\n@import \'~bootstrap/scss/dropdown\';\\n@import \'~bootstrap/scss/button-group\';\\n@import \'~bootstrap/scss/nav\';\\n@import \'~bootstrap/scss/navbar\';\\n@import \'~bootstrap/scss/card\';\\n@import \'~bootstrap/scss/accordion\';\\n@import \'~bootstrap/scss/breadcrumb\';\\n@import \'~bootstrap/scss/pagination\';\\n@import \'~bootstrap/scss/badge\';\\n@import \'~bootstrap/scss/alert\';\\n@import \'~bootstrap/scss/progress\';\\n@import \'~bootstrap/scss/list-group\';\\n@import \'~bootstrap/scss/close\';\\n@import \'~bootstrap/scss/toasts\';\\n@import \'~bootstrap/scss/modal\';\\n@import \'~bootstrap/scss/tooltip\';\\n@import \'~bootstrap/scss/popover\';\\n@import \'~bootstrap/scss/carousel\';\\n@import \'~bootstrap/scss/spinners\';\\n@import \'~bootstrap/scss/offcanvas\';\\n@import \'~bootstrap/scss/placeholders\';\\n\\n// Helpers\\n@import \'~bootstrap/scss/helpers\';\\n\\n// Utilities\\n@import \'~bootstrap/scss/utilities/api\';\\n// scss-docs-end import-stack\\n```\\n\\n> \ud83d\udca1 \u5c0f\u77e5\u8b58 :  \\n> \u95dc\u65bc\u70ba\u4ec0\u9ebc\u9084\u662f\u4f7f\u7528 `@import` \u4e0d\u4f7f\u7528 `@use`  \\n> \u53ef\u53c3\u8003 bootstrap issues \u8a0e\u8ad6\u904e `@import` \u7684\u554f\u984c  \\n> https://github.com/twbs/bootstrap/issues/35906\\n\\n\u63a5\u8457\u4f86\u5230 src/index.html \u5efa\u7acb html \u7d50\u69cb\u4e26\u5f15\u5165 scss\\n\\n```html\\n<!DOCTYPE html>\\n<html lang=\\"en\\">\\n\\t<head>\\n\\t\\t<meta charset=\\"UTF-8\\" />\\n\\t\\t<meta http-equiv=\\"X-UA-Compatible\\" content=\\"IE=edge\\" />\\n\\t\\t<meta name=\\"viewport\\" content=\\"width=device-width, initial-scale=1.0\\" />\\n\\t\\t<title>Document</title>\\n\\t\\t\x3c!-- \u5f15\u5165scss/app.scss --\x3e\\n\\t\\t<link rel=\\"stylesheet\\" href=\\"./scss/app.scss\\" />\\n\\t</head>\\n\\t<body>\\n\\t\\t\x3c!-- \u6293\u53d6 Bootstrap Buttons \u7d50\u69cb --\x3e\\n\\t\\t<button type=\\"button\\" class=\\"btn btn-primary\\">Primary</button>\\n\\t\\t<button type=\\"button\\" class=\\"btn btn-secondary\\">Secondary</button>\\n\\t\\t<button type=\\"button\\" class=\\"btn btn-success\\">Success</button>\\n\\t\\t<button type=\\"button\\" class=\\"btn btn-danger\\">Danger</button>\\n\\t\\t<button type=\\"button\\" class=\\"btn btn-warning\\">Warning</button>\\n\\t\\t<button type=\\"button\\" class=\\"btn btn-info\\">Info</button>\\n\\t\\t<button type=\\"button\\" class=\\"btn btn-light\\">Light</button>\\n\\t\\t<button type=\\"button\\" class=\\"btn btn-dark\\">Dark</button>\\n\\t\\t<button type=\\"button\\" class=\\"btn btn-link\\">Link</button>\\n\\t</body>\\n</html>\\n```\\n\\n\u63a5\u4e0b\u4f86\u8a2d\u7f6e Parcel building\\n\\npackage.json \u4fee\u6539\u524d\\n\\n```json\\n{\\n\\t\\"name\\": \\"proejct\\",\\n\\t\\"version\\": \\"1.0.0\\",\\n\\t\\"main\\": \\"index.js\\",\\n\\t\\"license\\": \\"MIT\\",\\n\\t\\"devDependencies\\": {\\n\\t\\t\\"parcel\\": \\"^2.5.0\\"\\n\\t},\\n\\t\\"dependencies\\": {\\n\\t\\t\\"bootstrap\\": \\"^5.1.3\\"\\n\\t}\\n}\\n```\\n\\n- \u52a0\u5165 scripts\\n- \u52a0\u5165 source\\n- \u79fb\u9664 main\\n\\npackage.json \u4fee\u6539\u5f8c\\n\\n```json\\n{\\n\\t\\"name\\": \\"proejct\\",\\n\\t\\"version\\": \\"1.0.0\\",\\n\\t\\"source\\": \\"src/index.html\\",\\n\\t\\"scripts\\": {\\n\\t\\t\\"start\\": \\"parcel\\",\\n\\t\\t\\"build\\": \\"parcel build\\"\\n\\t},\\n\\t\\"license\\": \\"MIT\\",\\n\\t\\"devDependencies\\": {\\n\\t\\t\\"parcel\\": \\"^2.5.0\\"\\n\\t},\\n\\t\\"dependencies\\": {\\n\\t\\t\\"bootstrap\\": \\"^5.1.3\\"\\n\\t}\\n}\\n```\\n\\n\u57f7\u884c\\n\\n```\\nyarn parcel\\n```\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1652673849797/lq2rp8Gcf.png align=\\"left\\")\\n\\n\u6210\u529f\u986f\u793a Bootstrap \u6a23\u5f0f\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1652673884177/za5MpRVpq.png align=\\"left\\")\\n\\n---\\n\\n## \u4e3b\u984c\\n\\n---\\n\\n\u6211\u5011\u5df2\u6210\u529f\u5c0e\u5165 Bootstrap  \\n\u4f46\u662f\u4f9d\u8a2d\u8a08\u7a3f\u5167\u5bb9\uff0c\u591a\u5c11\u9700\u8981\u66f4\u6539 Bootstrap \u7684\u4e3b\u984c\\n\\n1. \u984f\u8272\\n2. \u9593\u8ddd\\n3. \u884c\u9ad8\\n4. \u5404\u5f0f\u5404\u6a23\u7684\u5ba2\u88fd\u5316...\\n\\n\u6240\u4ee5\u9996\u5148\u5c0e\u5165\u8b8a\u6578  \\n\u63a1\u7528 [Sass 7-1 pattern](https://gist.github.com/rveitch/84cea9650092119527bc)\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1652674830701/Jp7sEnPyS.png align=\\"left\\")\\n\\n\u6211\u5011\u65b0\u589e components, pages, utils \u8cc7\u6599\u593e\uff0c\u5f8c\u9762\u53ef\u4ee5\u8996\u9700\u6c42\u518d\u589e\u52a0\u5230 7-1 \u898f\u683c  \\n\u63a5\u8457 utils \u5e95\u4e0b\u65b0\u589e \\\\_variables.scss \u6a94\u6848\uff0c\u586b\u5beb\u4ee5\u4e0b\u5167\u5bb9\\n\\n```scss\\n// \u5f15\u5165 bootstrap variables \u539f\u59cb\u8cc7\u6599\\n@import \'~bootstrap/scss/variables\';\\n\\n// \u524d\u5f80 @import \'~bootstrap/scss/variables\'; \u6a94\u6848\u5167\uff0c\u62c9\u53d6\u984f\u8272\u914d\u7f6e\u4e26\u628a !default \u522a\u6389\\n// scss-docs-start theme-color-variables\\n$primary: #ff0000; //$blue;\\n$secondary: $gray-600;\\n$success: $green;\\n$info: $cyan;\\n$warning: $yellow;\\n$danger: $red;\\n$light: $gray-100;\\n$dark: $gray-900;\\n// scss-docs-end theme-color-variables\\n\\n// scss-docs-start theme-colors-map\\n$theme-colors: (\\n\\t\'primary\': $primary,\\n\\t\'secondary\': $secondary,\\n\\t\'success\': $success,\\n\\t\'info\': $info,\\n\\t\'warning\': $warning,\\n\\t\'danger\': $danger,\\n\\t\'light\': $light,\\n\\t\'dark\': $dark,\\n);\\n// scss-docs-end theme-colors-map\\n```\\n\\n\u4e0a\u8ff0\u64cd\u4f5c\u5982\u4e0b\\n\\n1. \u5f15\u5165 bootstrap variables \u539f\u59cb\u8cc7\u6599\\n2. \u62c9\u53d6\u539f\u59cb\u8cc7\u6599\u7684\u984f\u8272\u914d\u7f6e\u4e26\u79fb\u9664 !default\\n3. \u6539\u8b8a\u4e3b\u984c\u8272 primary \u8272\u78bc\u70ba #ff0000\\n\\n\u63a5\u4e0b\u4f86\u524d\u5f80 src/scss/app.scss  \\n\u4fee\u6539`@import` variables \u8def\u5f91\\n\\n```scss\\n@import \'./utils/variables\'; // \'~bootstrap/scss/variables\';\\n```\\n\\n\u67e5\u770b\u7d50\u679c primary \u5df2\u8b8a\u66f4\u984f\u8272\u70ba #ff0000\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1652675587294/qO5nN0GNh.png align=\\"left\\")\\n\\n\u63a5\u4e0b\u4f86\u8acb\u4f9d\u6b64\u908f\u8f2f\uff0c\u7167\u8457\u9700\u6c42\u5ba2\u88fd\u5316\u4e3b\u984c\u5373\u53ef\u3002\\n\\n---\\n\\n## \u81ea\u5b9a\u7fa9 utilities \u5de5\u5177\\n\\n---\\n\\n\u5728 Bootstrap 4 \u7684\u6642\u4ee3\uff0c\u5c0d\u65bc Bootstrap \u4e0d\u8db3\u7684 utilities  \\n\u9700\u8981\u81ea\u5df1\u5beb scss.file \u6a94\u6848\u5f15\u5165.\\n\\n\u4f46\u662f Bootstrap 5 \u5df2\u7d93\u63d0\u4f9b\u5feb\u901f\u7684\u64b0\u5beb\u65b9\u5f0f~\ud83c\udf89  \\n\u8acb\u5230 src/scss/utils \u5e95\u4e0b\u65b0\u589e \\\\_utilities.scss \u586b\u5beb\u4ee5\u4e0b\u5167\u5bb9\\n\\n```scss\\n@import \'~bootstrap/scss/utilities\';\\n\\n$utilities: map-merge(\\n\\t$utilities,\\n\\t(\\n\\t\\t\'cursor\': (\\n\\t\\t\\tproperty: cursor,\\n\\t\\t\\tclass: cursor,\\n\\t\\t\\tresponsive: true,\\n\\t\\t\\tvalues: auto pointer grab,\\n\\t\\t),\\n\\t)\\n);\\n```\\n\\n\u8acb\u5230 src/scss/app.scss \u66ff\u63db @import utilities \u8def\u5f91\\n\\n```scss\\n@import \'./utils/utilities\'; //\'~bootstrap/scss/utilities\';\\n```\\n\\n\u8acb\u5230 src/index.html \u65b0\u589e\u4e0b\u9762\u5167\u5bb9\u505a\u6e2c\u8a66\\n\\n```html\\n<p class=\\"cursor-pointer\\">pointer</p>\\n```\\n\\n\u6210\u529f\u65b0\u589e cursor-pointer \u6a23\u5f0f\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1652676556639/cYIQSbzHm.png align=\\"left\\")\\n\\n> \ud83d\udca1 \u5c0f\u77e5\u8b58 :  \\n> \u60f3\u4e86\u89e3\u66f4\u591a utilities \u914d\u7f6e\u65b9\u6cd5\u8acb\u67e5\u770b\u5b98\u65b9\u6587\u4ef6  \\n> https://getbootstrap.com/docs/5.2/utilities/api/"},{"id":"/cl2oclcxw00fzkhnv02fy1wvo","metadata":{"permalink":"/zh/cl2oclcxw00fzkhnv02fy1wvo","source":"@site/blog/cl2oclcxw00fzkhnv02fy1wvo.md","title":"Toast 1 - Custom Error - JavaScript","description":"Toast 1 - Custom Error - JavaScript","date":"2022-05-02T00:00:00.000Z","formattedDate":"2022\u5e745\u67082\u65e5","tags":[{"label":"javascript","permalink":"/zh/tags/javascript"},{"label":"toast","permalink":"/zh/tags/toast"}],"readingTime":2.325,"truncated":true,"authors":[{"name":"Callum","title":"Front End Engineer","url":"https://github.com/callumzhong","imageURL":"https://github.com/callumzhong.png","key":"callum"}],"frontMatter":{"title":"Toast 1 - Custom Error - JavaScript","date":"2022-05-02T00:00:00.000Z","authors":"callum","tags":["javascript","toast"]},"prevItem":{"title":"Toast 2 - \u5feb\u901f\u5c0e\u5165 Bootstrap 5 \u9032\u884c\u958b\u767c","permalink":"/zh/cl3893xld06owmgnv8j2mfmgn"},"nextItem":{"title":"Mock API \u8eab\u70ba\u524d\u7aef\u8a72\u4e86\u89e3\u7684\u77e5\u8b58\u9ede","permalink":"/zh/cl22p6xo20a28y6nv9eq8ftij"}},"content":"## Toast 1 - Custom Error - JavaScript\\n\\n## \u524d\u8a00\\n\\n\u5e73\u5e38 Coding \u904e\u7a0b\u4e2d\uff0c\u6703\u4f7f\u7528\u6d41\u7a0b\u63a7\u5236\u9673\u8ff0\u5f0f / \u689d\u4ef6\u9673\u8ff0\u5f0f\u53bb\u64b0\u5beb\u4e00\u9805\u529f\u80fd\u9019\u662f\u5f88\u5e38\u898b\u7684\u3002\\n\u4f46\u662f\u67d0\u4e9b\u6642\u5019\u8f38\u5165\u7684\u503c\uff0c\u662f\u7121\u6cd5\u638c\u63e1\u7684\u3001\u662f\u5916\u90e8\u7684\u6c92\u8fa6\u6cd5\u9810\u671f\u7d50\u679c\uff0c\u53ea\u80fd\u9a57\u8b49\u5404\u65b9\u9762\u932f\u8aa4\u7684\u53ef\u80fd\u3002\\n\\n\x3c!--truncate--\x3e\\n\\n\u8209\u4f8b\u4f86\u8aaa\u64b0\u5beb POST \u884c\u70ba\u6642\uff0c\u7d66\u65bc\u65e2\u5b9a\u898f\u7bc4\u7684\u524d\u63d0\u4e0b\u8981\u9a57\u8b49\u4f7f\u7528\u8005\u662f\u5426\u6309\u898f\u5247\u8d70\u3002\\n\\n```javascript\\nfunction listener(req, res) {\\n\\tlet data = \'\';\\n\\treq.on(\'data\', (chunk) => {\\n\\t\\tdata += chunk;\\n\\t});\\n\\n\\tif (req.method === \'POST\') {\\n\\t\\treq.on(\'end\', () => {\\n\\t\\t\\ttry {\\n\\t\\t\\t\\tconst obj = JSON.parse(data);\\n\\t\\t\\t\\t// 1. \u9a57\u8b49 data \u662f\u5426\u70ba JSON String?\\n\\t\\t\\t\\t// 2. \u9a57\u8b49 obj.title \u662f\u5426\u6709\u503c?\\n\\t\\t\\t} catch (error) {\\n\\t\\t\\t\\tif (error instanceof SyntaxError) {\\n\\t\\t\\t\\t\\t// JSON parse error\\n\\t\\t\\t\\t}\\n\\t\\t\\t}\\n\\t\\t});\\n\\t}\\n}\\n```\\n\\n\u7576 POST \u5f8c\u6211\u5011\u8655\u7406\u597d buffer \u554f\u984c\uff0c\u9810\u8a2d\u898f\u7bc4\u4e0a\u5beb data \u662f JSON String \u8981\u8f49\u70ba Object\\n\u4f46\u662f\u767c\u751f\u683c\u5f0f\u4e0d\u5c0d JavaScript \u6703\u62cb SyntaxError \u4f8b\u5916\u932f\u8aa4 (Javascript \u8a9e\u6cd5\u932f\u8aa4\u7684 Error)\\n\\n\u554f\u984c\u662f\u9a57\u8b49 obj.title \u662f\u5426\u80fd\u6709\u4e00\u500b\u81ea\u5b9a\u7fa9\u7684\u932f\u8aa4\uff0c\u63d0\u4f9b\u7d66\u7a0b\u5f0f\u6d41\u7a0b\u5224\u65b7\u5462 \ud83e\udd14\\n\\n---\\n\\n## \u81ea\u5b9a\u7fa9\u932f\u8aa4\\n\\nJavaScript \u5c0d\u65bc Error \u6709\u6700\u4e0a\u5c64\u7684\u7269\u4ef6\u540d\u70ba Error\uff0c\u53ef\u4ee5\u4f7f\u7528 Class \u7e7c\u627f\u5b83\u4f86\u5ba2\u88fd\u5316\\n\\n```javascript\\nclass CustomizeError extends Error {\\n\\tconstructor(message) {\\n\\t\\tsuper(message);\\n\\t\\tthis.name = this.constructor.name;\\n\\t}\\n}\\n```\\n\\n\u900f\u904e super \u5b58\u53d6\u7236\u5c64\u628a message \u5b58\u9032\u53bb\uff0c\u63a5\u8457\u6211\u5011\u628a\u4e0a\u9762\u4f8b\u5b50\u62ff\u904e\u4f86\\n\\n```javascript\\nfunction listener(req, res) {\\n\\tlet data = \'\';\\n\\treq.on(\'data\', (chunk) => {\\n\\t\\tdata += chunk;\\n\\t});\\n\\n\\tif (req.method === \'POST\') {\\n\\t\\treq.on(\'end\', () => {\\n\\t\\t\\ttry {\\n\\t\\t\\t\\tconst obj = JSON.parse(data);\\n\\t\\t\\t\\tif (!obj?.title) {\\n\\t\\t\\t\\t\\tthrow new CustomizeError(\'title \u70ba\u5fc5\u586b\');\\n\\t\\t\\t\\t}\\n\\t\\t\\t} catch (error) {\\n\\t\\t\\t\\tif (error instanceof SyntaxError) {\\n\\t\\t\\t\\t\\tconsole.log(\'JSON parse error\');\\n\\t\\t\\t\\t}\\n\\t\\t\\t\\tif (error instanceof CustomizeError) {\\n\\t\\t\\t\\t\\tconsole.log(error.message);\\n\\t\\t\\t\\t}\\n\\t\\t\\t}\\n\\t\\t});\\n\\t}\\n}\\n```\\n\\n- JSON.parse(data) \u7576\u8a9e\u6cd5\u932f\u8aa4 JavaScript \u5f15\u64ce\u6703\u62cb\u4f8b\u5916\u932f\u8aa4 SyntaxError\\n- !obj?.title \u7576\u9a57\u8b49\u6c92\u6709 title \u5c6c\u6027\uff0c\u5c31\u6703\u62cb\u4f8b\u5916\u932f\u8aa4 CustomizeError\\n- \u9032\u5165 catch \u4f7f\u7528 instanceof \u5224\u65b7\uff0c\u53ef\u4ee5\u5ba2\u88fd\u5316\u5404 Error \u7269\u4ef6\u5f8c\u7e8c\u7684\u8655\u7406\\n\\n---\\n\\n## Reference\\n\\n[custom-errors \u53c3\u8003\u8cc7\u6599](https://javascript.info/custom-errors)"},{"id":"/cl22p6xo20a28y6nv9eq8ftij","metadata":{"permalink":"/zh/cl22p6xo20a28y6nv9eq8ftij","source":"@site/blog/cl22p6xo20a28y6nv9eq8ftij.md","title":"Mock API \u8eab\u70ba\u524d\u7aef\u8a72\u4e86\u89e3\u7684\u77e5\u8b58\u9ede","description":"Mock API \u8eab\u70ba\u524d\u7aef\u8a72\u4e86\u89e3\u7684\u77e5\u8b58\u9ede","date":"2022-04-17T00:00:00.000Z","formattedDate":"2022\u5e744\u670817\u65e5","tags":[{"label":"api","permalink":"/zh/tags/api"}],"readingTime":4.86,"truncated":true,"authors":[{"name":"Callum","title":"Front End Engineer","url":"https://github.com/callumzhong","imageURL":"https://github.com/callumzhong.png","key":"callum"}],"frontMatter":{"title":"Mock API \u8eab\u70ba\u524d\u7aef\u8a72\u4e86\u89e3\u7684\u77e5\u8b58\u9ede","date":"2022-04-17T00:00:00.000Z","authors":"callum","tags":["api"]},"prevItem":{"title":"Toast 1 - Custom Error - JavaScript","permalink":"/zh/cl2oclcxw00fzkhnv02fy1wvo"},"nextItem":{"title":"hashnode-blog-backup","permalink":"/zh/README"}},"content":"## Mock API \u8eab\u70ba\u524d\u7aef\u8a72\u4e86\u89e3\u7684\u77e5\u8b58\u9ede\\n\\n## \u7c21\u4ecb\\n\\nMock \u8a5e\u610f\u70ba\u6a21\u64ec\u7684\u610f\u601d\uff0c\u90a3\u9ebc\u5148\u4e86\u89e3\u70ba\u4ec0\u9ebc\u9700\u8981\u6a21\u64ec?\\n\\n\u6211\u5011\u6240\u958b\u767c\u7684\u7db2\u9801\u61c9\u7528\u7a0b\u5f0f\u5927\u90e8\u5206\u642d\u914d\u8cc7\u6599\u5eab\uff0c\u8f03\u5927\u578b\u7684\u7db2\u9801\u5247\u53ef\u80fd\u6703\u6709\u591a\u500b\u8907\u96dc\u7684\u8cc7\u6599\u5eab\uff0c\\n\u9019\u9700\u8981\u5f8c\u7aef\u958b\u767c\u4eba\u54e1\u7684\u5354\u4f5c\u3002\\n\\n\u4f46\u662f\u958b\u767c\u9700\u8981\u6642\u9593\u53bb\u5b8c\u6210\uff0c\u70ba\u4e86\u8b93\u6574\u9ad4\u958b\u767c\u6d41\u7a0b\u9806\u5229\uff0c\u5247\u6a21\u64ec API \u56de\u50b3\u6578\u64da\u6703\u662f\u597d\u7684\u89e3\u6c7a\u65b9\u6848\u3002\u53e6\u5916\u7db2\u9801\u6709\u4f7f\u7528\u7b2c\u4e09\u65b9 API \u7684\u8a71\uff0c\u5229\u7528 MOCK API \u65bc\u958b\u767c\u671f\u9593\u4e5f\u80fd\u964d\u4f4e\u8abf\u7528\u7b2c\u4e09\u65b9 API \u7684\u6210\u672c\u3002\\n\\n\x3c!--truncate--\x3e\\n\\n## \u9078\u64c7\u5de5\u5177\\n\\n\u5f9e\u7c21\u4ecb\u4e86\u89e3\u5230 MOCK API \u610f\u601d\u5f8c\u8a72\u600e\u9ebc\u5efa\u7acb\u5462 ?\\n\\n\u63a8\u85a6\u4f7f\u7528 [Mockoon](https://mockoon.com/) \u670d\u52d9\\n\\n- \u4e0d\u9700\u8981\u9060\u7aef\u90e8\u5c6c\\n- \u4e0d\u5fc5\u5efa\u7acb\u5e33\u6236\\n- \u514d\u8cbb\\n- \u958b\u6e90\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650151981989/GPoaCUppZ.png)\\n\\n> \u9ede\u64ca Download \u9078\u64c7\u4f60\u7684\u4f5c\u696d\u7cfb\u7d71\u4e0b\u8f09\u5373\u53ef\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650152090688/VLskL8iT1.png)\\n\\n> \u5b98\u7db2\u4e0a\u7684\u756b\u9762\u4ecb\u7d39\u5716\\n\\n\u5b89\u88dd\u597d\u5f8c\u8b93\u6211\u5011\u958b\u59cb\u5efa\u7acb\u7b2c\u4e00\u500b Mock API\\n\\n## \u4f7f\u7528 GUI \u5efa\u7acb MOCK API\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650152961205/snQyQLphp.png)\\n\\n\u6253\u958b mockoon \u6703\u770b\u5230\u5b98\u65b9\u7bc4\u4f8b API \uff0c\u6211\u5f9e\u9019\u908a\u4ee5\u5716\u793a\u4e0a\u7684\u7de8\u865f\u4ecb\u7d39\\n\\n1. environment \u662f Mock API \u74b0\u5883\u6a94 (\u5132\u5b58\u5728\u672c\u5730\u7aef\u7684 json)\\n2. Route \u662f\u8def\u7531\u4ee5 Mock \u74b0\u5883\u70ba\u76ee\u9304\u53ef\u5efa\u7acb\u591a\u500b API\\n3. Body \u662f Response Body\\n4. Headers \u662f\u8a72 Route \u7684 Headers\\n5. Headers \u662f\u8a72 Mock API \u74b0\u5883\u6a94\u7684 Headers (\u9032\u53bb\u6709\u6309\u9215\u53ef\u4ee5\u52a0\u5165 CORS \u8de8\u57df)\\n\\n> \u5176\u5be6\u756b\u9762\u975e\u5e38\u76f4\u89c0\u6c92\u4ec0\u9ebc\u597d\u8b1b\u7684\uff0c\u4f46\u662f\u6e4a\u5b57\u6578\u518d\u52a0\u9ede\u5716\u793a\\n\\n- \u65b0\u589e environment\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650153917658/XLs4HIOHh.png)\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650153986990/GnNWAJmXJ.png)\\n\\n- \u65b0\u589e\u8def\u7531\\n  ![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650154207079/s3fO_11Wn.png)\\n\\n\u5230\u6b64\u505c\u4e00\u4e0b\uff0c\u6211\u5011\u52a0\u5165\u7279\u5225\u4f86\u8cd3 [SWAPI API](https://swapi.dev/) \u4f86\u6a21\u64ec\u5b83\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650154941393/SIpSEQ4Jy.png)\\n\\n## \u5982\u4f55\u904b\u884c\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650155083643/STjmPd9kH.png)\\n\\n- \u53ef\u4ee5\u540c\u6642\u628a\u591a\u500b\u74b0\u5883\u6a94\u904b\u884c\u8d77\u4f86\uff0c\u4f46\u8981\u5c0f\u5fc3 PORT \u4e0d\u8981\u885d\u7a81 (mockoon \u6709\u9632\u5446\u6a5f\u5236)\\n- \u8a2d\u5b9a PORT \u7684\u65b9\u5f0f\u5728\u4e0a\u65b9 Settings > API URL \u6a19\u984c\u90a3\u500b\u5340\u584a\\n\\n## \u5efa\u7acb\u96a8\u6a5f\u6578\u64da\\n\\n> \u505a\u5047\u9700\u8981\u81ea\u5df1\u6253\u8cc7\u6599\uff0c\u9084\u662f\u505a\u5047\u55ce?\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650159740005/EuDSOrjam.png)\\n\\n\u53f3\u4e0b\u65b9\u6709 open templating documemtation \u53ef\u4ee5\u9ede\u64ca\u67e5\u770b\u6a23\u677f\u6587\u4ef6\\n\u4ee5\u661f\u969b\u5927\u6230\u70ba\u4f8b\u5b50\u3002\\n\\n```json\\n{\\n\\t\\"name\\": \\"Luke Skywalker\\",\\n\\t\\"height\\": \\"172\\",\\n\\t\\"mass\\": \\"77\\",\\n\\t\\"hair_color\\": \\"blond\\",\\n\\t\\"skin_color\\": \\"fair\\",\\n\\t\\"eye_color\\": \\"blue\\",\\n\\t\\"birth_year\\": \\"19BBY\\",\\n\\t\\"gender\\": \\"male\\",\\n\\t\\"homeworld\\": \\"https://swapi.dev/api/planets/1/\\",\\n\\t\\"films\\": [\\n\\t\\t\\"https://swapi.dev/api/films/1/\\",\\n\\t\\t\\"https://swapi.dev/api/films/2/\\",\\n\\t\\t\\"https://swapi.dev/api/films/3/\\",\\n\\t\\t\\"https://swapi.dev/api/films/6/\\"\\n\\t],\\n\\t\\"species\\": [],\\n\\t\\"vehicles\\": [\\n\\t\\t\\"https://swapi.dev/api/vehicles/14/\\",\\n\\t\\t\\"https://swapi.dev/api/vehicles/30/\\"\\n\\t],\\n\\t\\"starships\\": [\\n\\t\\t\\"https://swapi.dev/api/starships/12/\\",\\n\\t\\t\\"https://swapi.dev/api/starships/22/\\"\\n\\t],\\n\\t\\"created\\": \\"2014-12-09T13:50:51.644000Z\\",\\n\\t\\"edited\\": \\"2014-12-20T21:17:56.891000Z\\",\\n\\t\\"url\\": \\"https://swapi.dev/api/people/1/\\"\\n}\\n```\\n\\n\u52a0\u5165\u96a8\u6a5f\u6578\u64da\\n\\n```json\\n[\\n       {{#repeat 500}}\\n  {\\n  \\"name\\": \\"{{faker \'name.firstName\'}} {{faker \'name.lastName\'}}\\",\\n  \\"height\\": \\"{{faker \'random.number\' min=100 max=999}}\\",\\n  \\"mass\\": \\"77\\",\\n  \\"hair_color\\": \\"blond\\",\\n  \\"skin_color\\": \\"fair\\",\\n  \\"eye_color\\": \\"blue\\",\\n  \\"birth_year\\": \\"19BBY\\",\\n  \\"gender\\": \\"male\\",\\n  \\"homeworld\\": \\"https://swapi.dev/api/planets/{{faker \'random.number\'}}/\\",\\n  \\"films\\": [\\n       {{#repeat 2}}\\n        \\"https://swapi.dev/api/films/1/{{faker \'random.number\'}}\\"\\n       {{/repeat}}\\n  ],\\n  \\"species\\": [],\\n  \\"vehicles\\": [\\n    \\"https://swapi.dev/api/vehicles/14/\\",\\n    \\"https://swapi.dev/api/vehicles/30/\\"\\n  ],\\n  \\"starships\\": [\\n    \\"https://swapi.dev/api/starships/12/\\",\\n    \\"https://swapi.dev/api/starships/22/\\"\\n  ],\\n  \\"created\\": \\"2014-12-09T13:50:51.644000Z\\",\\n  \\"edited\\": \\"2014-12-20T21:17:56.891000Z\\",\\n  \\"url\\": \\"https://swapi.dev/api/people/1/\\"\\n}\\n     {{/repeat}}\\n]\\n```\\n\\n- \u4f7f\u7528 faker \u4e82\u6578 / \u540d\u5b57\\n- \u4f7f\u7528 repeat \u7522\u751f\u6307\u5b9a\u6578\u91cf\u7684\u5167\u5bb9\\n\\n## Route Rules\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650160778810/uN24qivpB.png)\\n\\n\u4f60\u53ef\u4ee5\u5c0d API \u5efa\u7acb Requset \u898f\u5247\u3002\\n\u5047\u8a2d\u6a21\u64ec Login API \u6307\u5b9a\u67d0\u500b\u4f7f\u7528\u8005\u5e33\u865f\u624d\u53ef\u767b\u5165\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650161899924/FCrb77FM2.png)\\n\\n- \u5b9a\u7fa9 Header Content-Type \u70ba application/json\\n- \u5b9a\u7fa9 body \u5c6c\u6027\u6709 username \u503c\u662f example@gmail.com\\n- \u5b9a\u7fa9 body \u5c6c\u6027\u6709 password \u503c\u662f 1234\\n\\n\u8a2d\u5b9a\u5b8c\u5f8c\u8a18\u5f97\u518d\u52a0\u4e00\u500b Response \u70ba 401 \u9806\u5e8f\u8981\u66ff\u63db\u4e00\u4e0b\u9810\u8a2d\u662f 401\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650162276149/Boo0m91f5.png)\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650165089362/KbNAbuNSb.png)\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650165106998/DKmBB5V1g.png)\\n\\n## OpenAPI \u898f\u7bc4\u6587\u4ef6\u5c0e\u5165\\n\\n- mockoon \u652f\u63f4\u5c0e\u5165 OpenAPI \u6587\u4ef6\uff0c\u524d\u5f8c\u7aef\u6e9d\u901a\u5c0d\u65bc API \u5927\u90e8\u5206\u9700\u8981\u6587\u4ef6\u6e1b\u5c11\u4e0d\u5fc5\u8981\u7684\u6587\u5b57\u8a0e\u8ad6 (\u6216\u7269\u7406\u8a0e\u8ad6)\u3002\\n\\n\u6587\u4ef6\u64b0\u5beb\u5de5\u5177\u5982\u4e0b\\n\\n- [API blueprint\\n  ](https://apiblueprint.org/) \u63cf\u8ff0 API \u67b6\u69cb\u7684\u8a9e\u8a00\\n- [apib2swagger npm package](https://github.com/kminami/apib2swagger) \u8f49\u70ba openapi \u683c\u5f0f\\n\\n\u9019\u6a23\u5c31\u5f97\u5230 openapi \u683c\u5f0f\u7684\u6a94\u6848\u56c9\\n\\n- \u532f\u5165 mockoon\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650157069690/5ENqzDHzf.png)\\n\\n- \u532f\u5165 json / yaml \u90fd\u53ef\u4ee5\\n- \u532f\u51fa\u53ea\u80fd\u9078\u64c7 json\\n\\n## Proxy \u4ee3\u7406\u7b2c\u4e09\u65b9 API\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650163845782/3DWUQV6sZ.png)\\n\\n\u56de\u5230\u958b\u982d\u6709\u63d0\u5230\u4ee3\u7406\u529f\u80fd\uff0c\u7167\u8457\u4f9d\u4e0a\u5716\u6307\u793a\u8f38\u5165\u5f8c (\u4ee5 SWAPI API \u70ba\u4f8b)\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650163975332/ZBSoCKlaF.png)\\n\\n\u8a2d\u7f6e\u597d\u5f8c\u958b\u555f postman \u6e2c\u8a66\uff0c\u539f\u7406\u4e0a\u662f\u547c\u53eb\u6c92\u6709\u914d\u7f6e\u7684 route \u6703\u5e6b\u4f60\u8f49\u767c\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650164029659/xFkYKBosu.png)\\n\\n![image.png](https://cdn.hashnode.com/res/hashnode/image/upload/v1650164055097/akH_PTGmj.png)\\n\\n\u5169\u5f35\u5716\u6bd4\u5c0d\u8cc7\u6599\u4e00\u81f4\u3002\\n\\n## Q&A\\n\\nQ: \u7528\u6236\u7aef\u53ef\u4ee5 POST \u8cc7\u6599\u5132\u5b58\u5728 mockoon server \u55ce?\\n\\nmockoon \u6c92\u6709\u63d0\u4f9b\u8cc7\u6599\u5132\u5b58\uff0c\u4ee5\u4e0b\u63d0\u4f9b\u65b9\u6848\\n\\n- [json server](https://github.com/typicode/json-server)\\n- [mockswith](https://mockswitch.com/)\\n\\n## \u5ef6\u4f38\u95b1\u8b80\\n\\n- [Run your mock REST APIs anywhere with Mockoon CLI](https://mockoon.com/tutorials/run-mock-api-anywhere-cli/)\\n- [mockoon \u5b98\u7db2](https://mockoon.com/)\\n- [apib \u5b98\u7db2](https://apiblueprint.org/)"},{"id":"/README","metadata":{"permalink":"/zh/README","source":"@site/blog/README.md","title":"hashnode-blog-backup","description":"\u4ecb\u7d39","date":"2022-04-15T14:57:51.000Z","formattedDate":"2022\u5e744\u670815\u65e5","tags":[],"readingTime":0.235,"truncated":false,"authors":[],"frontMatter":{},"prevItem":{"title":"Mock API \u8eab\u70ba\u524d\u7aef\u8a72\u4e86\u89e3\u7684\u77e5\u8b58\u9ede","permalink":"/zh/cl22p6xo20a28y6nv9eq8ftij"},"nextItem":{"title":"\u5982\u4f55\u914d\u7f6e gitconfig \u9023\u7dda\u591a\u500b GitHub \u5e33\u865f (window)","permalink":"/zh/cl20zjal106moy6nv550s5ofg"}},"content":"## \u4ecb\u7d39\\n\\n\u8a72\u90e8\u843d\u683c\u6587\u7ae0\u7531 [hashnode](https://callum.hashnode.dev/) \u64b0\u5beb\u4e26\u62f7\u8c9d\u904e\u4f86\uff0c\u4ee5\u5229\u4f9b\u6700\u4f73\u5316\u641c\u5c0b\\n\\n## \u624b\u52d5\u914d\u7f6e docusaurus\\n\\nExamples:\\n\\n```\\n---\\ntitle: \u6587\u7ae0\u6a19\u984c\\ndate: 2022-05-02\\nauthors: callum\\ntags: [api]\\n---\\n```"},{"id":"/cl20zjal106moy6nv550s5ofg","metadata":{"permalink":"/zh/cl20zjal106moy6nv550s5ofg","source":"@site/blog/cl20zjal106moy6nv550s5ofg.md","title":"\u5982\u4f55\u914d\u7f6e gitconfig \u9023\u7dda\u591a\u500b GitHub \u5e33\u865f (window)","description":"\u5982\u4f55\u914d\u7f6e gitconfig \u9023\u7dda\u591a\u500b GitHub \u5e33\u865f (window)","date":"2022-04-15T00:00:00.000Z","formattedDate":"2022\u5e744\u670815\u65e5","tags":[{"label":"github","permalink":"/zh/tags/github"},{"label":"ssh","permalink":"/zh/tags/ssh"}],"readingTime":3.155,"truncated":true,"authors":[{"name":"Callum","title":"Front End Engineer","url":"https://github.com/callumzhong","imageURL":"https://github.com/callumzhong.png","key":"callum"}],"frontMatter":{"title":"\u5982\u4f55\u914d\u7f6e gitconfig \u9023\u7dda\u591a\u500b GitHub \u5e33\u865f (window)","date":"2022-04-15T00:00:00.000Z","authors":"callum","tags":["github","ssh"]},"prevItem":{"title":"hashnode-blog-backup","permalink":"/zh/README"}},"content":"## \u5982\u4f55\u914d\u7f6e gitconfig \u9023\u7dda\u591a\u500b GitHub \u5e33\u865f (window)\\n\\n## \u5efa\u7acb SSH\\n\\n\u958b\u555f\u7d42\u7aef\u6a5f(\u5feb\u6377\u9375 win+q \u8f38\u5165 cmd)\uff0c\u63a5\u8457\u6309\u7167\u6b65\u9a5f\u5f80\u4e0b\u8d70\\n\\n```\\nssh-keygen\\n```\\n\\n\x3c!--truncate--\x3e\\n\\n\u7cfb\u7d71\u6703\u8a62\u554f ssh \u5b58\u653e\u4f4d\u7f6e (\u5efa\u8b70\u96c6\u4e2d\u64fa\u653e .ssh \u8cc7\u6599\u593e, \u6a94\u540d\u5247\u8a2d\u7f6e id_rsa_username)\\n\\n- \u5982\u679c\u4e0d\u9700\u8981\u66ff\u63db\u5247\u6309 enter\\n- \u9700\u8981\u66ff\u63db\u8acb\u8f38\u5165\u5b8c\u6574\u8def\u5f91\u5305\u542b id_rsa \u662f\u6a94\u540d\\n\\n```\\nGenerating public/private rsa key pair.\\nEnter file in which to save the key (/home/username/.ssh/id_rsa):\\n```\\n\\nssh \u662f\u5426\u8981\u8a2d\u5b9a\u5bc6\u78bc\uff0c\u5982\u4e0d\u9700\u8981\u8acb\u6309 enter\\n\\n```\\nEnter passphrase (empty for no passphrase):\\nEnter same passphrase again:\\n```\\n\\n\u63a5\u8457\u53bb ssh \u5b58\u653e\u4f4d\u7f6e\u67e5\u770b ssh \u5df2\u7522\u751f\u4e86\u6c92 ?\\n\\n- id_rsa (\u79c1\u9470)\\n- id_rsa_pub(\u516c\u9470)\\n\\n> \u516c\u9470\u662f\u8981\u8907\u88fd\u5167\u5bb9\u653e\u5728\u4f3a\u670d\u5668\u9a57\u8b49\u7684\uff0c\u79c1\u9470\u5247\u662f\u81ea\u5df1\u4fdd\u5b58\u3002\\n> \u7576\u628a\u8cc7\u6599\u63a8\u4e0a\u4f3a\u670d\u5668\u6642\u6703\u4ee5\u79c1\u9470\u9a57\u8b49\u516c\u9470\u3002\\n\\n## \u8a2d\u5b9a config\\n\\n**\u8acb\u5148\u6839\u64da\u4f60\u7684\u5e33\u865f\u6578\uff0c\u5efa\u7acb\u5c0d\u61c9\u6578\u91cf\u7684 SSH \u518d\u5f80\u4e0b\u95b1\u8b80**\\n\\n1. \u524d\u5f80 .ssh \u8cc7\u6599\u593e\u65b0\u589e config \u6a94\u6848 (\u5efa\u7acb text \u518d\u9023\u540c\u526f\u6a94\u540d \u4e00\u4f75\u522a\u6389\u6539\u6210 config)\\n2. \u4f9d\u4e0b\u65b9\u586b\u5beb\u5167\u5bb9\uff0c\u628a username1 \u63db\u6210\u4f60\u7684 username\\n\\n```\\n#username1 account\\nHost github.com-username1\\n    HostName github.com\\n    User git\\n    IdentityFile ~/.ssh/id_rsa_username1\\n\\n#username2 account\\nHost github.com-username2\\n    HostName github.com\\n    User git\\n    IdentityFile ~/.ssh/id_rsa_username2\\n```\\n\\n## \u8a2d\u5b9a gitconfig\\n\\n1. \u63a5\u8457\u4f86\u5230\u4f60\u7684\u4f7f\u7528\u8005\u8def\u5f91\u5e95\u4e0b\uff0c\u627e\u5168\u57df gitconfig \u6a94\u6848\u4f4d\u7f6e\\n2. \u65bc\u8cc7\u6599\u593e\u5167\u5efa\u7acb gitconfig-username1, gitconfig-username2\\n   \u5206\u5225\u8a2d\u5b9a user, email\\n\\n```\\n# gitconfig-username1\\n[user]\\n\\tname = username1\\n\\temail = username1@gmail.com\\n```\\n\\n```\\n# gitconfig-username2\\n[user]\\n\\tname = username2\\n\\temail = username2@gmail.com\\n```\\n\\n\u63a5\u8457\u6253\u958b gitconfig \u52a0\u5165\u4ee5\u4e0b\u8a2d\u5b9a\\n\\n```\\n[includeIf \\"gitdir/i:E:/Documents/Code/username1/\\"]\\n\\tpath = ~/.gitconfig-username1\\n[includeIf \\"gitdir/i:E:/Documents/Code/username2/\\"]\\n\\tpath = ~/.gitconfig-username2\\n```\\n\\n\u4e0a\u9762\u7684\u610f\u601d\\n\\n- \u7576 git \u7684\u5132\u5b58\u5eab\u5728 username1 \u8cc7\u6599\u593e\u5e95\u4e0b\u6642\u5f15\u5165 ~/.gitconfig-username1 \u6a94\u6848\\n- username2 \u5c31\u4ee5\u6b64\u985e\u63a8...\\n\\n## \u6e2c\u8a66\\n\\n\u4e0a\u8ff0\u6b65\u9a5f\u5b8c\u6210\u5f8c\u6211\u5011\u958b\u59cb\u6e2c\u8a66\u4e00\u4e0b\u74b0\u5883\uff0c\u5148\u5207\u63db\u5230 username1 \u5e95\u4e0b\\n\\n```\\ncd E:/Documents/Code/username1\\n```\\n\\n\u5efa\u7acb project \u4e26\u4e14\u5728 project \u8cc7\u6599\u593e\u5167 git init (\u521d\u59cb\u5316)\\n\\n```\\nPS E:\\\\Documents\\\\Code\\\\username1\\\\project> git init\\n```\\n\\n\u63a5\u8457\u8f38\u5165 git config user.name\\n\\n```\\nPS E:\\\\Documents\\\\Code\\\\username1\\\\project> git config user.name\\n```\\n\\n\u56de\u50b3 username1 \u5c31\u8868\u793a\u8a2d\u5b9a\u6210\u529f\u56c9\uff0c\u63a5\u4e0b\u4f86\u8a66\u8457\u4f7f\u7528 ssh \u514b\u9686 GitHub \u5132\u5b58\u5eab\\n\\n\u4e0b\u9762\u662f\u4f60\u5728 GitHub ssh \u8907\u88fd\u53d6\u5230\u7684\u5b57\u4e32\\n\\n```\\ngit@github.com:username1/example.git\\n```\\n\\n\u8acb\u6539\u6210\\n\\n```\\ngit@github.com-username1:username1/example.git\\n```\\n\\n\u56e0\u70ba\u8acb\u5f80\u4e0a\u56de\u770b config \u6211\u5011\u5df2\u7d93\u5e6b github.com \u5206\u6d41\\n\\n- github.com-username1\\n- github.com-username2\\n\\n\u63a5\u4e0b\u4f86\u5c31\u53ef\u4ee5\u8f38\u5165\u4e0b\u9762\u6307\u4ee4\\n\\n```\\ngit clone git@github.com-username1:username1/example.git\\n```\\n\\n\u7d50\u675f\u9019\u6a23\u5c31\u6210\u529f\u505a\u597d\u5340\u5206\u5169\u500b git \u672c\u5730 user \u5169\u500b github \u5e33\u6236\\n\\n## \u7e3d\u7d50\\n\\n\u7576\u4f60\u8eab\u5206\u662f username1 \u7684\u6642\u5019\u9032\u884c\u958b\u767c\uff0c\u8acb\u628a git \u5132\u5b58\u5eab\u5efa\u7acb\u5728 E:\\\\Documents\\\\Code\\\\username1\\\\ \u5e95\u4e0b\\n\\n\u7576\u4f60\u8eab\u5206\u662f username2 \u7684\u6642\u5019\u9032\u884c\u958b\u767c\uff0c\u8acb\u628a git \u5132\u5b58\u5eab\u5efa\u7acb\u5728 E:\\\\Documents\\\\Code\\\\username2\\\\ \u5e95\u4e0b"}]}')}}]);